function id(a){return document.getElementById(a)}function cls(a){return document.getElementsByClassName(a)}let kindaction=cls('option-item');for(var i=0;i<kindaction.length;i++)kindaction[i].onclick=function(){for(var a=0;a<kindaction.length;a++)kindaction[a].classList.remove('active');this.classList.add('active');let b=this.getAttribute('data-tab');b=="social-media"?(id('social-media').classList.add('active'),id('contact-form').classList.remove('active')):(id('social-media').classList.remove('active'),id('contact-form').classList.add('active'))}